function escOut = fEscMakerV01(esc,nmb)%% return strings with escape factor '%d\t,,,\n'%% escOut = fEscMakerV01(esc,nmb)% ecs: escape factor string, like %d or %f% nmb: number of escape factors you want, >2% escOut: output string%% Written by Kei Nakamura% Created on Friday, june 8th 2007.% Modified on %% main bodyescOut = [esc '\t'];for ii=2:nmb-1    escOut = [escOut esc '\t'];endescOut = [escOut esc '\n'];
